8482 VPReplicateRecipe *VPRecipeBuilder::handleReplication(Instruction *I,
8483                                                       VFRange &Range) {
8484   bool IsUniform = LoopVectorizationPlanner::getDecisionAndClampRange(
8485       [&](ElementCount VF) { return CM.isUniformAfterVectorization(I, VF); },
8486       Range);
